import sys, json, csv
import io

def run(input_data):
    csv_text = input_data.get('csv', '')
    if not csv_text:
        return {'error': 'csv input is required'}

    reader = csv.DictReader(io.StringIO(csv_text))
    rows = list(reader)

    if not rows:
        return {'error': 'no data rows found', 'columns': reader.fieldnames or []}

    summary = {}
    for col in reader.fieldnames:
        values = [row[col] for row in rows]
        numeric = []
        for v in values:
            try:
                numeric.append(float(v))
            except ValueError:
                pass

        col_info = {
            'count': len(values),
            'unique': len(set(values)),
            'sample': values[:3],
        }
        if numeric:
            col_info['type'] = 'numeric'
            col_info['min'] = min(numeric)
            col_info['max'] = max(numeric)
            col_info['avg'] = sum(numeric) / len(numeric)
        else:
            col_info['type'] = 'text'
        summary[col] = col_info

    return {'summary': summary, 'row_count': len(rows), 'columns': reader.fieldnames}

result = run(input_data)
print(json.dumps(result))
